| MCP:jccFVu | plugins {
| MCP:jccFVu |     id 'java-library'
| MCP:jccFVu |     id 'org.springframework.boot' apply(false)
| MCP:jccFVu |     id 'io.spring.dependency-management'
| MCP:jccFVu |     id 'io.spring.javaformat' apply(false)
| MCP:jccFVu |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:jccFVu | }
| MCP:jccFVu | 
| MCP:jccFVu | apply from: 'lint.gradle'
| MCP:jccFVu | 
| MCP:jccFVu | allprojects {
| MCP:jccFVu |     group = "${projectGroup}"
| MCP:jccFVu |     version = "${applicationVersion}"
| MCP:jccFVu | 
| MCP:jccFVu |     repositories {
| MCP:jccFVu |         mavenCentral()
| MCP:jccFVu |     }
| MCP:jccFVu | }
| MCP:jccFVu | 
| MCP:jccFVu | subprojects {
| MCP:jccFVu |     apply plugin: 'java-library'
| MCP:jccFVu |     apply plugin: 'org.springframework.boot'
| MCP:jccFVu |     apply plugin: 'io.spring.dependency-management'
| MCP:jccFVu |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:jccFVu |     
| MCP:jccFVu |     dependencyManagement {
| MCP:jccFVu |         imports {
| MCP:jccFVu |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:jccFVu |         }
| MCP:jccFVu |     }
| MCP:jccFVu | 
| MCP:jccFVu |     dependencies {
| MCP:jccFVu |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:jccFVu |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:jccFVu |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:jccFVu |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:jccFVu |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:jccFVu |         testImplementation 'org.assertj:assertj-core'
| MCP:jccFVu |         testImplementation 'org.mockito:mockito-core'
| MCP:jccFVu |     }
| MCP:jccFVu | 
| MCP:jccFVu |     java {
| MCP:jccFVu |         toolchain {
| MCP:jccFVu |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:jccFVu |         }
| MCP:jccFVu |     }
| MCP:jccFVu | 
| MCP:jccFVu |     bootJar.enabled = false
| MCP:jccFVu |     jar.enabled = true
| MCP:jccFVu | 
| MCP:jccFVu |     test {
| MCP:jccFVu |         useJUnitPlatform {
| MCP:jccFVu |             excludeTags 'develop', 'restdocs'
| MCP:jccFVu |         }
| MCP:jccFVu |     }
| MCP:jccFVu | 
| MCP:jccFVu |     testing {
| MCP:jccFVu |         suites {
| MCP:jccFVu |             test {
| MCP:jccFVu |                 targets {
| MCP:jccFVu |                     unitTest {
| MCP:jccFVu |                         testTask.configure {
| MCP:jccFVu |                             group = 'verification'
| MCP:jccFVu |                             useJUnitPlatform {
| MCP:jccFVu |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:jccFVu |                             }
| MCP:jccFVu |                         }
| MCP:jccFVu |                     }
| MCP:jccFVu | 
| MCP:jccFVu |                     contextTest {
| MCP:jccFVu |                         testTask.configure {
| MCP:jccFVu |                             group = 'verification'
| MCP:jccFVu |                             useJUnitPlatform {
| MCP:jccFVu |                                 includeTags 'context'
| MCP:jccFVu |                             }
| MCP:jccFVu |                         }
| MCP:jccFVu |                     }
| MCP:jccFVu | 
| MCP:jccFVu |                     restDocsTest {
| MCP:jccFVu |                         testTask.configure {
| MCP:jccFVu |                             group = 'verification'
| MCP:jccFVu |                             useJUnitPlatform {
| MCP:jccFVu |                                 includeTags 'restdocs'
| MCP:jccFVu |                             }
| MCP:jccFVu |                         }
| MCP:jccFVu |                     }
| MCP:jccFVu | 
| MCP:jccFVu |                     developTest {
| MCP:jccFVu |                         testTask.configure {
| MCP:jccFVu |                             group = 'verification'
| MCP:jccFVu |                             useJUnitPlatform {
| MCP:jccFVu |                                 includeTags 'develop'
| MCP:jccFVu |                             }
| MCP:jccFVu |                         }
| MCP:jccFVu |                     }
| MCP:jccFVu |                 }
| MCP:jccFVu |             }
| MCP:jccFVu |         }
| MCP:jccFVu |     }
| MCP:jccFVu | 
| MCP:jccFVu |     tasks.named('asciidoctor').configure {
| MCP:jccFVu |         dependsOn restDocsTest
| MCP:jccFVu |     }
| MCP:jccFVu | }

| MCP:jccFVu | subprojects {
| MCP:jccFVu |     apply plugin: 'java'
| MCP:jccFVu |     apply plugin: 'io.spring.javaformat'
| MCP:jccFVu | 
| MCP:jccFVu |     dependencies {
| MCP:jccFVu |         compileOnly "io.spring.javaformat:spring-javaformat-gradle-plugin:${springJavaFormatVersion}"
| MCP:jccFVu |     }
| MCP:jccFVu | }
